import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as o,e as c}from"./app-be253e4c.js";const s={},d=c(`<h1 id="col命令" tabindex="-1"><a class="header-anchor" href="#col命令" aria-hidden="true">#</a> col命令</h1><p>在很多<code>UNIX</code>说明文件里，都有<code>RLF</code>控制字符，当我们把说明文件的内容输出成纯文本文件时，控制字符会变成乱码，<code>col</code>命令则能有效滤除这些控制字符。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>col <span class="token punctuation">[</span>options<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-b, --no-backspaces</code>: 过滤掉所有的控制字符，包括<code>RLF</code>和<code>HRLF</code>。</li><li><code>-f, --fine</code>: 允许前半行换行，通常在半行边界上打印的字符会在下一行上打印，滤除<code>RLF</code>字符，但允许将<code>HRLF</code>字符呈现出来。</li><li><code>-p, --pass</code>: 传递未知控制序列，通常<code>col</code>将从输入中过滤出除自身识别和解释的以外的任何控制序列。</li><li><code>-h, --tabs</code>: 将空格转换为制表符，这是默认设置。</li><li><code>-x, --spaces</code>: 将制表符转换为空格。</li><li><code>-l, --lines NUM</code>: 在内存中至少缓冲<code>num</code>行，默认情况下缓存<code>128</code>行。</li><li><code>-V, --version</code>: 输出版本信息。</li><li><code>-H, --help</code>: 输出帮助信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>将<code>col</code>的帮助文档过滤掉反向换行符<code>RLF</code>后保存到<code>col.txt</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>col <span class="token parameter variable">--help</span> <span class="token operator">|</span> col <span class="token operator">&gt;</span> col.txt
</code></pre></div><p>将<code>col</code>的帮助文档过滤掉控制字符后保存到<code>col.txt</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>col <span class="token parameter variable">--help</span> <span class="token operator">|</span> col <span class="token parameter variable">-b</span> <span class="token operator">&gt;</span> col.txt
</code></pre></div><p>将<code>col</code>的帮助文档的制表符转换为空格后保存到<code>col.txt</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>col <span class="token parameter variable">--help</span> <span class="token operator">|</span> col <span class="token parameter variable">-x</span> <span class="token operator">&gt;</span> col.txt
</code></pre></div>`,13),l=[d];function n(t,r){return a(),o("div",null,l)}const h=e(s,[["render",n],["__file","col.html.vue"]]);export{h as default};
